"use strict";const e=require("../utils/request.js");exports.createVenue=function(t){return e.post("/venues",t)},exports.deleteVenue=function(t){return e.del(`/venues/${t}`)},exports.getGeneratedDates=function(t){return e.get(`/timeslots/venue/${t}/generated-dates`)},exports.getMyManagedVenues=function(){return e.get("/venues/manager/me")},exports.getVenueDetail=function(t){return e.get(`/venues/${t}`,{},{cache:!1})},exports.getVenueTimeslots=function(t,n){return e.get(`/timeslots/venue/${t}/date/${n}`)},exports.updateTimeslotStatus=function(t,n){return e.patch(`/timeslots/${t}/status`,n)},exports.updateVenue=function(t,n){return e.put(`/venues/${t}`,n)},exports.updateVenueStatus=function(t,n){return e.patch(`/venues/${t}/status`,n)};
